const ligas_permitidas = [
  'liga mx', 'champions league', 'premier league', 'la liga',
  'serie a', 'bundesliga', 'ligue 1', 'mls', 'liga de expansión'
];

const partidos = $input.first().json.data || [];

const filtrados = partidos.filter(p => {
  const liga = (p.league || p.competition || '').toLowerCase();
  return ligas_permitidas.some(l => liga.includes(l));
});

return filtrados.map(p => ({ json: p }));

// Node 11: Code: Calcular Probabilidades

// Helper function for Poisson distribution
function factorial(n) {
    if (n === 0 || n === 1) return 1;
    let result = 1;
    for (let i = 2; i <= n; i++) {
        result *= i;
    }
    return result;
}

function poisson(lambda, k) {
    return (Math.pow(lambda, k) * Math.exp(-lambda)) / factorial(k);
}

const match = $input.item[0].json;
const homeStats = $input.item[1].json; // From HTTP: Stats Equipo Local
const awayStats = $input.item[2].json; // From HTTP: Stats Equipo Visitante
const h2hData = $input.item[3].json; // From HTTP: H2H

const predictions = {};

// Default values for stats if API returns 404 or timeout
const defaultAvgGoalsScored = 1.2;
const defaultAvgGoalsConceded = 1.2;
const defaultBttsPercentage = 0.50;
const defaultOver25Percentage = 0.52;
const defaultAvgCorners = 5.5; // Assuming a reasonable default

// Extract stats with fallbacks
// Assuming the /football/teams/{teamId}/stats endpoint returns these directly
const avg_goals_scored_home = homeStats?.avg_goals_scored || defaultAvgGoalsScored;
const avg_goals_conceded_home = homeStats?.avg_goals_conceded || defaultAvgGoalsConceded;
const avg_corners_home = homeStats?.avg_corners || defaultAvgCorners;
const btts_percentage_home = homeStats?.btts_percentage || defaultBttsPercentage;
const over25_percentage_home = homeStats?.over25_percentage || defaultOver25Percentage;

const avg_goals_scored_away = awayStats?.avg_goals_scored || defaultAvgGoalsScored;
const avg_goals_conceded_away = awayStats?.avg_goals_conceded || defaultAvgGoalsConceded;
const avg_corners_away = awayStats?.avg_corners || defaultAvgCorners;
const btts_percentage_away = awayStats?.btts_percentage || defaultBttsPercentage;
const over25_percentage_away = awayStats?.over25_percentage || defaultOver25Percentage;

// MARKET 1 — 1X2 (Local / Empate / Visitante)
let probLocal = 0;
let probEmpate = 0;
let probVisitante = 0;

try {
    let home_strength = avg_goals_scored_home / avg_goals_conceded_away;
    let away_strength = avg_goals_scored_away / avg_goals_conceded_home;
    const home_advantage_factor = 1.1;

    probLocal = (home_strength * home_advantage_factor) / (home_strength * home_advantage_factor + away_strength);
    probVisitante = away_strength / (home_strength * home_advantage_factor + away_strength);
    probEmpate = 1 - probLocal - probVisitante;

    // Adjust draw probability if difference in strengths is small
    if (Math.abs(home_strength - away_strength) < 0.2) { // Arbitrary small difference threshold
        probEmpate = Math.max(probEmpate, 0.15);
        const remainingProb = 1 - probEmpate;
        probLocal = probLocal / (probLocal + probVisitante) * remainingProb;
        probVisitante = probVisitante / (probLocal + probVisitante) * remainingProb;
    }
} catch (e) {
    console.error("Error calculating 1X2 probabilities:", e);
    // Fallback to default or skip if critical
}

predictions['1X2_Local'] = probLocal;
predictions['1X2_Empate'] = probEmpate;
predictions['1X2_Visitante'] = probVisitante;

// MARKET 2 — Over/Under 2.5 Goles
let prob_final_over25 = 0;
try {
    const xG_total_esperado = avg_goals_scored_home + avg_goals_scored_away;

    const p0 = poisson(xG_total_esperado, 0);
    const p1 = poisson(xG_total_esperado, 1);
    const p2 = poisson(xG_total_esperado, 2);

    const pUnder2_5 = p0 + p1 + p2;
    const pOver2_5 = 1 - pUnder2_5;

    const historical_over25 = (over25_percentage_home + over25_percentage_away) / 2;
    prob_final_over25 = (pOver2_5 * 0.60) + (historical_over25 * 0.40);
} catch (e) {
    console.error("Error calculating Over/Under 2.5 probabilities:", e);
}
predictions['Over2.5_Goles'] = prob_final_over25;

// MARKET 3 — BTTS (Ambos Anotan)
let pBTTS = 0;
try {
    const btts_home = btts_percentage_home;
    const btts_away = btts_percentage_away;

    pBTTS = (btts_home + btts_away) / 2;

    // Adjustment
    if (avg_goals_scored_home < 0.8 || avg_goals_scored_away < 0.8) {
        pBTTS = pBTTS - 0.10; // Subtract 10%
    }
} catch (e) {
    console.error("Error calculating BTTS probabilities:", e);
}
predictions['BTTS_Si'] = pBTTS;

// MARKET 4 — Corners Over/Under
let pOver9_5Corners = 0;
try {
    const avg_corners_total = avg_corners_home + avg_corners_away;

    if (avg_corners_total > 12.5) {
        pOver9_5Corners = 0.88;
    } else if (avg_corners_total > 11.5) {
        pOver9_5Corners = 0.80;
    } else if (avg_corners_total > 10.5) {
        pOver9_5Corners = 0.70;
    }

    // Adjustment H2H: Assuming h2hData.matches is an array of past matches with a 'totalCorners' field
    if (h2hData && h2hData.matches && h2hData.matches.length > 0) {
        let over9_5_count = 0;
        for (const h2hMatch of h2hData.matches) {
            if (h2hMatch.totalCorners && h2hMatch.totalCorners > 9.5) {
                over9_5_count++;
            }
        }
        if (over9_5_count / h2hData.matches.length >= 0.8) {
            pOver9_5Corners += 0.05; // Add 5%
        }
    }
} catch (e) {
    console.error("Error calculating Corners Over/Under probabilities:", e);
}
predictions['Corners_Over9.5'] = pOver9_5Corners;

// MARKET 5 — Doble Oportunidad
predictions['DobleOportunidad_1X'] = probLocal + probEmpate;
predictions['DobleOportunidad_X2'] = probEmpate + probVisitante;
predictions['DobleOportunidad_12'] = probLocal + probVisitante;

// Ensure probabilities are between 0 and 1
for (const key in predictions) {
    predictions[key] = Math.max(0, Math.min(1, predictions[key]));
}

return [{ json: { ...match, predictions } }];

// Node 12: Code: Filtrar >=75%
const item = $input.first().json;
const filteredPredictions = {};
let hasHighConfidencePick = false;

for (const market in item.predictions) {
    if (item.predictions[market] >= 0.75) {
        filteredPredictions[market] = item.predictions[market];
        hasHighConfidencePick = true;
    }
}

if (hasHighConfidencePick) {
    return [{ json: { ...item, filteredPredictions } }];
} else {
    return [{ json: { skip: true } }];
}

// Node 15: Code: Formatear Mensaje Telegram
const allPicks = $input.first().json.picks;

let message = '⚽ *PICKS DEL DÍA* — ' + new Date().toLocaleDateString('es-MX', { day: '2-digit', month: '2-digit', year: 'numeric' }) + '
';
message += '🎯 Solo pronósticos ≥75% confianza
';
message += '━━━━━━━━━━━━━━━━━━━━━

';

if (!allPicks || allPicks.length === 0) {
    message = 'Sin picks de alta confianza hoy 🔍';
} else {
    for (const pick of allPicks) {
        const match = pick.json;
        message += `🏟️ *${match.homeTeam} vs ${match.awayTeam}*
`;
        message += `🏆 ${match.league} | ⏰ ${match.time} CDMX
`; // Using match.league and match.time as per original prompt

        for (const market in match.filteredPredictions) {
            const probability = (match.filteredPredictions[market] * 100).toFixed(0);
            let emoji = '⚪'; // Default emoji
            if (probability >= 85) {
                emoji = '🟢';
            } else if (probability >= 75) {
                emoji = '🟡';
            }

            let predictionText = '';
            let marketName = '';

            // Map market keys to display names and prediction values
            switch (market) {
                case '1X2_Local': marketName = '1X2'; predictionText = 'Local'; break;
                case '1X2_Empate': marketName = '1X2'; predictionText = 'Empate'; break;
                case '1X2_Visitante': marketName = '1X2'; predictionText = 'Visitante'; break;
                case 'Over2.5_Goles': marketName = 'Over/Under 2.5 Goles'; predictionText = 'Over 2.5'; break;
                case 'BTTS_Si': marketName = 'BTTS'; predictionText = 'Sí'; break;
                case 'Corners_Over9.5': marketName = 'Corners Over/Under'; predictionText = 'Over 9.5'; break;
                case 'DobleOportunidad_1X': marketName = 'Doble Oportunidad'; predictionText = '1X'; break;
                case 'DobleOportunidad_X2': marketName = 'Doble Oportunidad'; predictionText = 'X2'; break;
                case 'DobleOportunidad_12': marketName = 'Doble Oportunidad'; predictionText = '12'; break;
                default: marketName = market; predictionText = 'N/A';
            }

            message += `${emoji} ${marketName}: *${predictionText}*
`;
            message += `📊 Confianza: ${probability}% ${emoji}
`;
        }
        message += '─────────────
';
    }
    message += '📌 Total picks: ' + allPicks.length + '
';
    message += '⚠️ _Solo con fines informativos. Apuesta responsablemente._';
}

return [{ json: { telegramMessage: message } }];
